What does this program print?

```cpp
#include <iostream>

class Base {
public:
    virtual std::string id() const { return "Base"; }
};

class Derived : public Base {
public:
    std::string id() const override { return "Derived"; }
};

void report(Base b) {
    std::cout << b.id() << "\n";
}

int main() {
    Derived d;
    report(d);
}
```

What does this program print?

```cpp
#include <iostream>

class Shape {
public:
    virtual std::string kind() const { return "Shape"; }
};

class Square : public Shape {
public:
    std::string kind() const override { return "Square"; }
};

int main() {
    Square sq;
    const Shape& ref = sq;  // reference, not value
    std::cout << ref.kind() << "\n";
}
